{"meta": null, "content": [{"type": "text", "text": "{"content":"348: // compareTaskCost compares cost of curTask and bestTask and returns whether curTask's cost is smaller than bestTask's.\n349: func compareTaskCost(curTask, bestTask base.Task, op *optimizetrace.PhysicalOptimizeOp) (curIsBetter bool, err error) {\n350: \tcurCost, curInvalid, err := getTaskPlanCost(curTask, op)\n351: \tif err != nil {\n352: \t\treturn false, err\n353: \t}\n354: \tbestCost, bestInvalid, err := getTaskPlanCost(bestTask, op)\n355: \tif err != nil {\n356: \t\treturn false, err\n357: \t}\n358: \tif curInvalid {\n359: \t\treturn false, nil\n360: \t}\n361: \tif bestInvalid {\n362: \t\treturn true, nil\n363: \t}\n364: \treturn curCost \u003c bestCost, nil\n365: }\n366: \n367: // getTaskPlanCost returns the cost of this task.\n368: // The new cost interface will be used if EnableNewCostInterface is true.\n369: // The second returned value indicates whether this task is valid.\n370: func getTaskPlanCost(t base.Task, pop *optimizetrace.PhysicalOptimizeOp) (float64, bool, error) {\n371: \tif t.Invalid() {\n372: \t\treturn math.MaxFloat64, true, nil\n373: \t}\n374: \n375: \t// use the new cost interface\n376: \tvar (\n377: \t\ttaskType         property.TaskType\n378: \t\tindexPartialCost float64\n379: \t)\n380: \tswitch t.(type) {\n381: \tcase *RootTask:\n382: \t\ttaskType = property.RootTaskType\n383: \tcase *CopTask: // no need to know whether the task is single-read or double-read, so both CopSingleReadTaskType and CopDoubleReadTaskType are OK\n384: \t\tcop := t.(*CopTask)\n385: \t\tif cop.indexPlan != nil \u0026\u0026 cop.tablePlan != nil { // handle IndexLookup specially\n386: \t\t\ttaskType = property.CopMultiReadTaskType\n387: \t\t\t// keep compatible with the old cost interface, for CopMultiReadTask, the cost is idxCost + tblCost.\n388: \t\t\tif !cop.indexPlanFinished { // only consider index cost in this case\n389: \t\t\t\tidxCost, err := getPlanCost(cop.indexPlan, taskType, optimizetrace.NewDefaultPlanCostOption().WithOptimizeTracer(pop))\n390: \t\t\t\treturn idxCost, false, err\n391: \t\t\t}\n392: \t\t\t// consider both sides\n393: \t\t\tidxCost, err := getPlanCost(cop.indexPlan, taskType, optimizetrace.NewDefaultPlanCostOption().WithOptimizeTracer(pop))\n394: \t\t\tif err != nil {\n395: \t\t\t\treturn 0, false, err\n396: \t\t\t}\n397: \t\t\ttblCost, err := getPlanCost(cop.tablePlan, taskType, optimizetrace.NewDefaultPlanCostOption().WithOptimizeTracer(pop))\n398: \t\t\tif err != nil {\n399: \t\t\t\treturn 0, false, err\n400: \t\t\t}\n401: \t\t\treturn idxCost + tblCost, false, nil\n402: \t\t}\n403: \n404: \t\ttaskType = property.CopSingleReadTaskType\n405: \n406: \t\t// TiFlash can run cop task as well, check whether this cop task will run on TiKV or TiFlash.\n407: \t\tif cop.tablePlan != nil {\n408: \t\t\tleafNode := cop.tablePlan\n409: \t\t\tfor len(leafNode.Children()) \u003e 0 {\n410: \t\t\t\tleafNode = leafNode.Children()[0]\n411: \t\t\t}\n412: \t\t\tif tblScan, isScan := leafNode.(*PhysicalTableScan); isScan \u0026\u0026 tblScan.StoreType == kv.TiFlash {\n413: \t\t\t\ttaskType = property.MppTaskType\n414: \t\t\t}\n415: \t\t}\n416: \n417: \t\t// Detail reason ref about comment in function `convertToIndexMergeScan`\n418: \t\t// for cop task with {indexPlan=nil, tablePlan=xxx, idxMergePartPlans=[x,x,x], indexPlanFinished=true} we should\n419: \t\t// plus the partial index plan cost into the final cost. Because t.plan() the below code used only calculate the\n420: \t\t// cost about table plan.\n421: \t\tif cop.indexPlanFinished \u0026\u0026 len(cop.idxMergePartPlans) != 0 {\n422: \t\t\tfor _, partialScan := range cop.idxMergePartPlans {\n423: \t\t\t\tpartialCost, err := getPlanCost(partialScan, taskType, optimizetrace.NewDefaultPlanCostOption().WithOptimizeTracer(pop))\n424: \t\t\t\tif err != nil {\n425: \t\t\t\t\treturn 0, false, err\n426: \t\t\t\t}\n427: \t\t\t\tindexPartialCost += partialCost\n428: \t\t\t}\n429: \t\t}\n430: \tcase *MppTask:\n431: \t\ttaskType = property.MppTaskType\n432: \tdefault:\n433: \t\treturn 0, false, errors.New(\"unknown task type\")\n434: \t}\n435: \tif t.Plan() == nil {\n436: \t\t// It's a very special case for index merge case.\n437: \t\t// t.plan() == nil in index merge COP case, it means indexPlanFinished is false in other words.\n438: \t\tcost := 0.0\n439: \t\tcopTsk := t.(*CopTask)\n440: \t\tfor _, partialScan := range copTsk.idxMergePartPlans {\n441: \t\t\tpartialCost, err := getPlanCost(partialScan, taskType, optimizetrace.NewDefaultPlanCostOption().WithOptimizeTracer(pop))\n442: \t\t\tif err != nil {\n443: \t\t\t\treturn 0, false, err\n444: \t\t\t}\n445: \t\t\tcost += partialCost\n446: \t\t}\n447: \t\treturn cost, false, nil\n448: \t}\n449: \tcost, err := getPlanCost(t.Plan(), taskType, optimizetrace.NewDefaultPlanCostOption().WithOptimizeTracer(pop))\n450: \treturn cost + indexPartialCost, false, err\n451: ","url":"https://sourcegraph.sourcegraph.com/github.com/sg-evals/tidb--v8.5.0@35f068e97ee53cbbd95f242e756b767b32c4f860/-/blob/pkg/planner/core/find_best_task.go%3FL348-450"}", "annotations": null, "meta": null}], "structuredContent": {"content": "348: // compareTaskCost compares cost of curTask and bestTask and returns whether curTask's cost is smaller than bestTask's.
