{"meta": null, "content": [{"type": "text", "text": "{"content":"100: \tif len(is.AccessConds) == 0 {\n101: \t\tis.Ranges = ranger.FullRange()\n102: \t}\n103: \tis.IdxCols, is.IdxColLens = expression.IndexInfo2PrefixCols(is.Columns, selfSchema.Columns, is.Index)\n104: \tis.FullIdxCols, is.FullIdxColLens = expression.IndexInfo2Cols(is.Columns, selfSchema.Columns, is.Index)\n105: \tif !is.Index.Unique \u0026\u0026 !is.Index.Primary \u0026\u0026 len(is.Index.Columns) == len(is.IdxCols) {\n106: \t\thandleCol := is.GetPKIsHandleCol(selfSchema)\n107: \t\tif handleCol != nil \u0026\u0026 !mysql.HasUnsignedFlag(handleCol.RetType.GetFlag()) {\n108: \t\t\tis.IdxCols = append(is.IdxCols, handleCol)\n109: \t\t\tis.IdxColLens = append(is.IdxColLens, types.UnspecifiedLength)\n110: \t\t}\n111: \t}\n112: \treturn is.StatsInfo(), nil\n113: }\n114: \n115: func deriveStats4DataSource(lp base.LogicalPlan, colGroups [][]*expression.Column) (*property.StatsInfo, error) {\n116: \tds := lp.(*logicalop.DataSource)\n117: \tif ds.StatsInfo() != nil \u0026\u0026 len(colGroups) == 0 {\n118: \t\treturn ds.StatsInfo(), nil\n119: \t}\n120: \tinitStats(ds, colGroups)\n121: \tif ds.StatsInfo() != nil {\n122: \t\t// Just reload the GroupNDVs.\n123: \t\tselectivity := ds.StatsInfo().RowCount / ds.TableStats.RowCount\n124: \t\tds.SetStats(ds.TableStats.Scale(selectivity))\n125: \t\treturn ds.StatsInfo(), nil\n126: \t}\n127: \tif ds.SCtx().GetSessionVars().StmtCtx.EnableOptimizerDebugTrace {\n128: \t\tdebugtrace.EnterContextCommon(ds.SCtx())\n129: \t\tdefer debugtrace.LeaveContextCommon(ds.SCtx())\n130: \t}\n131: \t// two preprocess here.\n132: \t// 1: PushDownNot here can convert query 'not (a != 1)' to 'a = 1'.\n133: \t// 2: EliminateNoPrecisionCast here can convert query 'cast(c\u003cint\u003e as bigint) = 1' to 'c = 1' to leverage access range.\n134: \texprCtx := ds.SCtx().GetExprCtx()\n135: \tfor i, expr := range ds.PushedDownConds {\n136: \t\tds.PushedDownConds[i] = expression.PushDownNot(exprCtx, expr)\n137: \t\tds.PushedDownConds[i] = expression.EliminateNoPrecisionLossCast(exprCtx, ds.PushedDownConds[i])\n138: \t}\n139: \tfor _, path := range ds.PossibleAccessPaths {\n140: \t\tif path.IsTablePath() {\n141: \t\t\tcontinue\n142: \t\t}\n143: \t\terr := fillIndexPath(ds, path, ds.PushedDownConds)\n144: \t\tif err != nil {\n145: \t\t\treturn nil, err\n146: \t\t}\n147: \t}\n148: \t// TODO: Can we move ds.deriveStatsByFilter after pruning by heuristics? In this way some computation can be avoided\n149: \t// when ds.PossibleAccessPaths are pruned.\n150: \tds.SetStats(deriveStatsByFilter(ds, ds.PushedDownConds, ds.PossibleAccessPaths))\n151: \terr := derivePathStatsAndTryHeuristics(ds)\n152: \tif err != nil {\n153: \t\treturn nil, err\n154: \t}\n155: \n156: \tif err := generateIndexMergePath(ds); err != nil {\n157: \t\treturn nil, err\n158: \t}\n159: \n160: \tif ds.SCtx().GetSessionVars().StmtCtx.EnableOptimizerDebugTrace {\n161: \t\tdebugTraceAccessPaths(ds.SCtx(), ds.PossibleAccessPaths)\n162: \t}\n163: \tds.AccessPathMinSelectivity = getMinSelectivityFromPaths(ds.PossibleAccessPaths, float64(ds.TblColHists.RealtimeCount))\n164: \n165: \treturn ds.StatsInfo(), nil\n166: }\n167: \n168: func fillIndexPath(ds *logicalop.DataSource, path *util.AccessPath, conds []expression.Expression) error {\n169: \tif ds.SCtx().GetSessionVars().StmtCtx.EnableOptimizerDebugTrace {\n170: \t\tdebugtrace.EnterContextCommon(ds.SCtx())\n171: \t\tdefer debugtrace.LeaveContextCommon(ds.SCtx())\n172: \t}\n173: \tpath.Ranges = ranger.FullRange()\n174: \tpath.CountAfterAccess = float64(ds.StatisticTable.RealtimeCount)\n175: \tpath.IdxCols, path.IdxColLens = expression.IndexInfo2PrefixCols(ds.Columns, ds.Schema().Columns, path.Index)\n176: \tpath.FullIdxCols, path.FullIdxColLens = expression.IndexInfo2Cols(ds.Columns, ds.Schema().Columns, path.Index)\n177: \tif !path.Index.Unique \u0026\u0026 !path.Index.Primary \u0026\u0026 len(path.Index.Columns) == len(path.IdxCols) {\n178: \t\thandleCol := ds.GetPKIsHandleCol()\n179: \t\tif handleCol != nil \u0026\u0026 !mysql.HasUnsignedFlag(handleCol.RetType.GetFlag()) {\n180: \t\t\talreadyHandle := false\n181: \t\t\tfor _, col := range path.IdxCols {\n182: \t\t\t\tif col.ID == model.ExtraHandleID || col.EqualColumn(handleCol) {\n183: \t\t\t\t\talreadyHandle = true\n184: \t\t\t\t}\n185: \t\t\t}\n186: \t\t\t// Don't add one column twice to the index. May cause unexpected errors.\n187: \t\t\tif !alreadyHandle {\n188: \t\t\t\tpath.IdxCols = append(path.IdxCols, handleCol)\n189: \t\t\t\tpath.IdxColLens = append(path.IdxColLens, types.UnspecifiedLength)\n190: \t\t\t\t// Also updates the map that maps the index id to its prefix column ids.\n191: \t\t\t\tif len(ds.TableStats.HistColl.Idx2ColUniqueIDs[path.Index.ID]) == len(path.Index.Columns) {\n192: \t\t\t\t\tds.TableStats.HistColl.Idx2ColUniqueIDs[path.Index.ID] = append(ds.TableStats.HistColl.Idx2ColUniqueIDs[path.Index.ID], handleCol.UniqueID)\n193: \t\t\t\t}\n194: \t\t\t}\n195: \t\t}\n196: \t}\n197: \terr := detachCondAndBuildRangeForPath(ds.SCtx(), path, conds, ds.TableStats.HistColl)\n198: \treturn err\n199: }\n200: \n201: // deriveIndexPathStats will fulfill the information that the AccessPath need.\n202: // conds is the conditions used to generate the DetachRangeResult for path.\n203: // isIm indicates whether this function is called to generate the partial path for IndexMerge.\n204: func deriveIndexPathStats(ds *logicalop.DataSource, path *util.AccessPath, _ []expression.Expression, isIm bool) {\n205: \tif ds.SCtx().GetSessionVars().StmtCtx.EnableOptimizerDebugTrace {\n206: \t\tdebugtrace.EnterContextCommon(ds.SCtx())\n207: \t\tdefer debugtrace.LeaveContextCommon(ds.SCtx())\n208: \t}\n209: \tif path.EqOrInCondCount == len(path.AccessConds) {\n210: \t\taccesses, remained := path.SplitCorColAccessCondFromFilters(ds.SCtx(), path.EqOrInCondCount)\n211: \t\tpath.AccessConds = append(path.AccessConds, accesses...)\n212: \t\tpath.TableFilters = remained\n213: \t\tif 