201: // deriveIndexPathStats will fulfill the information that the AccessPath need.
202: // conds is the conditions used to generate the DetachRangeResult for path.
203: // isIm indicates whether this function is called to generate the partial path for IndexMerge.
204: func deriveIndexPathStats(ds *logicalop.DataSource, path *util.AccessPath, _ []expression.Expression, isIm bool) {
205: 	if ds.SCtx().GetSessionVars().StmtCtx.EnableOptimizerDebugTrace {
206: 		debugtrace.EnterContextCommon(ds.SCtx())
207: 		defer debugtrace.LeaveContextCommon(ds.SCtx())
208: 	}
209: 	if path.EqOrInCondCount == len(path.AccessConds) {
210: 		accesses, remained := path.SplitCorColAccessCondFromFilters(ds.SCtx(), path.EqOrInCondCount)
211: 		path.AccessConds = append(path.AccessConds, accesses...)
212: 		path.TableFilters = remained
213: 		if len(accesses) > 0 && ds.StatisticTable.Pseudo {
214: 			path.CountAfterAccess = cardinality.PseudoAvgCountPerValue(ds.StatisticTable)
215: 		} else {
216: 			selectivity := path.CountAfterAccess / float64(ds.StatisticTable.RealtimeCount)
217: 			for i := range accesses {
218: 				col := path.IdxCols[path.EqOrInCondCount+i]
219: 				ndv := cardinality.EstimateColumnNDV(ds.StatisticTable, col.ID)
220: 				ndv *= selectivity
221: 				if ndv < 1 {
222: 					ndv = 1.0
223: 				}
224: 				path.CountAfterAccess = path.CountAfterAccess / ndv
225: 			}
226: 		}
227: 	}
228: 	var indexFilters []expression.Expression
229: 	indexFilters, path.TableFilters = splitIndexFilterConditions(ds, path.TableFilters, path.FullIdxCols, path.FullIdxColLens)
230: 	path.IndexFilters = append(path.IndexFilters, indexFilters...)
231: 	// If the `CountAfterAccess` is less than `stats.RowCount`, there must be some inconsistent stats info.
232: 	// We prefer the `stats.RowCount` because it could use more stats info to calculate the selectivity.
233: 	if path.CountAfterAccess < ds.StatsInfo().RowCount && !isIm {
234: 		path.CountAfterAccess = math.Min(ds.StatsInfo().RowCount/cost.SelectionFactor, float64(ds.StatisticTable.RealtimeCount))
235: 	}
236: 	if path.IndexFilters != nil {
237: 		selectivity, _, err := cardinality.Selectivity(ds.SCtx(), ds.TableStats.HistColl, path.IndexFilters, nil)
238: 		if err != nil {
239: 			logutil.BgLogger().Debug("calculate selectivity failed, use selection factor", zap.Error(err))
240: 			selectivity = cost.SelectionFactor
241: 		}
242: 		if isIm {
243: 			path.CountAfterIndex = path.CountAfterAccess * selectivity
244: 		} else {
245: 			path.CountAfterIndex = math.Max(path.CountAfterAccess*selectivity, ds.StatsInfo().RowCount)
246: 		}
247: 	} else {
248: 		path.CountAfterIndex = path.CountAfterAccess
249: 	}
250: }
